module.exports = /*#__PURE__*/JSON.parse('[{"title":"Noteshell","type":"startup","alias":"noteshell","imageAlias":"tech-connect","headline":"Co-founder building a multimodal learning platform","timeline":"Present","searchDescription":"Top 10% Y Combinator Winter 2025 startup with personalized recommendations, an agentic study assistant, and an MCP tool layer.","longDescription":"At Noteshell, I co-founded a multimodal learning platform focused on making studying more adaptive and useful. We shipped personalized recommendations, an agentic study assistant, and an MCP tool layer that connected learning workflows into one product experience. The company was recognized in the Top 10% of Y Combinator Winter 2025.","tech":["Multimodal Systems","Agents","MCP","Recommendations","Product","Startup"],"links":[{"name":"website","url":"link-outline.svg","link":"https://app.noteshell.io"}]},{"title":"Kintsugi Hearts Dream","type":"creative","alias":"kintsugi-hearts-dream","imageAlias":"meetmidway","headline":"AI pop music video directed and delivered end to end","timeline":"Chroma Awards 2025","searchDescription":"Directed a 4:29 AI pop music video from concept to 4K master around the theme of choosing each other in love.","longDescription":"Kintsugi Hearts Dream is a 4:29 AI pop music video I directed and delivered end to end, including concept, story, lyrics, shot plan, and final 4K master. The project centered on the message: love lasts when we keep choosing each other, even in first love. I composed and produced the duet in Suno v5 with custom structure and stems, mixed and mastered it in Ableton Live with a Novation MK3 controller, and exported release-ready versions for YouTube, Spotify, Instagram, and Facebook. I also built and ran a multi-model generative pipeline across Suno, Midjourney, OpenArt, WAN/Kling, Nanobanana, ElevenLabs, Topaz Video AI, and CapCut Pro while managing prompts, visual references, stems, and versioned assets.","tech":["Suno v5","Ableton Live","Midjourney","OpenArt","WAN","Kling","ElevenLabs","Topaz Video AI","CapCut Pro"],"videoEmbed":"https://www.youtube.com/embed/RwH7jThYDWw","links":[{"name":"video","url":"video-outline.svg","link":"https://youtu.be/RwH7jThYDWw"}]},{"title":"Lovealot.Together","type":"project","alias":"lovealot","imageAlias":"bumblebee","headline":"COO and data analyst for a 400K-follower creator operation","timeline":"Sep 2022 - May 2025","searchDescription":"Built a TikTok ETL and analytics pipeline that processed 100K+ engagement signals across 10 countries and drove a 5% lift.","longDescription":"As Chief Operating Officer and Data Analyst at Lovealot.Together, I built a TikTok ETL and analytics pipeline in Python and SQL that processed more than 100K engagement signals across 10 countries. That system improved content decision-making, helped drive a 5% engagement lift through automation, and supported partnerships with Vietnam’s #1 pay TV provider.","tech":["Python","SQL","ETL","Analytics","Growth","TikTok"],"mediaFrames":[{"type":"image","src":"/search-img/lovealot-detail.png","alt":"Lovealot Together detail"}],"links":[]},{"title":"AI Hire AI","type":"hackathon","alias":"ai-hire-ai","imageAlias":"aws","imageFit":"contain","headline":"Multi-agent copilot that saved 120 seconds per application","timeline":"AWS Hackathon 2026","searchDescription":"Built action-taking agents that auto-plan, prefill forms, and adapt end-to-end across job application flows.","longDescription":"Built with AWS Bedrock, Amazon Nova, Nova Act, OpenClaw, Python, TypeScript, and Docker, AI Hire AI acted as a multi-agent copilot for job applications. The system saved roughly 120 seconds per application by running applications in parallel with agents that could plan, prefill forms, and adapt actions end to end. I also built a recruiter agent that performed automatic social screening and adjusted its behavior across recruiter platforms.","tech":["AWS Bedrock","Amazon Nova","Nova Act","OpenClaw","Python","TypeScript","Docker"],"videoEmbed":"https://www.youtube.com/embed/P7I0xYGE_fA","mediaFrames":[{"type":"image","src":"/search-img/ai-hire-ai-tech-stack.png","alt":"AI Hire AI AWS hack tech stack"},{"type":"image","src":"/search-img/ai-hire-ai-flow.png","alt":"AI Hire AI flow diagram"}],"links":[{"name":"website","url":"link-outline.svg","link":"https://ai-hire-ai.vercel.app/"},{"name":"video","url":"video-outline.svg","link":"https://youtu.be/P7I0xYGE_fA"}]},{"title":"AI Financial Coach","type":"hackathon","alias":"ai-financial-coach","imageAlias":"renew","headline":"AI budgeting agent with iMessage delivery","timeline":"HackPrinceton 2025","searchDescription":"Developed an AI financial coach that predicts purchases and sends personalized advice through iMessage.","longDescription":"Built with Python, Snowflake, Gemini, DigitalOcean, Node.js, React, Knot, and Photon, this AI financial coach predicted upcoming purchases and delivered personalized budgeting advice through iMessage. The product focused on practical financial guidance, timely nudges, and a more conversational user experience.","tech":["Python","Snowflake","Gemini","DigitalOcean","Node.js","React","Knot","Photon"],"links":[]},{"title":"Productivity Agent","type":"hackathon","alias":"productivity-agent","imageAlias":"aws","imageFit":"contain","headline":"Real-time productivity agent built at AWS Hackathon","timeline":"AWS Hackathon 2025","searchDescription":"Built an agent that senses work across apps, creates concise work briefs, and recommends next-best actions.","longDescription":"Built with Python, AWS Lambda, AWS API Gateway, Nova, Bedrock, DynamoDB, and S3, this productivity agent sensed user context across apps, turned that context into concise work briefs, and recommended next-best actions. The system integrated a Chrome extension with AWS Lambda and Bedrock and increased task resumption rate by 35% by helping users re-enter work faster.","tech":["Python","AWS Lambda","AWS API Gateway","Nova","Bedrock","DynamoDB","S3"],"videoEmbed":"https://www.youtube.com/embed/o7Vgaxnxu34","links":[{"name":"video","url":"video-outline.svg","link":"https://youtu.be/o7Vgaxnxu34"}]},{"title":"AI Medical Research Tool","type":"project","alias":"ai-medical-research-tool","imageAlias":"ibm","imageFit":"contain","headline":"RAG app for trustworthy, page-cited medical syntheses","timeline":"IBM Challenge 2025","searchDescription":"Built a medical research tool using watsonx.ai Granite models and parallelized retrieval across dozens of papers.","longDescription":"This RAG web app was built with Python, Flask, IBM watsonx.ai, IBM Granite, watsonx.data, and React. It generates trustworthy, page-cited medical syntheses for researchers and supports multi-document reasoning across dozens of scientific papers at once by parallelizing retrieval and context chunking through watsonx.data pipelines.","tech":["Python","Flask","IBM watsonx.ai","IBM Granite","watsonx.data","React"],"links":[]},{"title":"Generative AI: Singing Voice Synthesis","type":"project","alias":"singing-voice-synthesis","imageAlias":"muto","headline":"Speech model and data pipeline for AI-generated singing","timeline":"Nov 2023 - Mar 2024","searchDescription":"Reduced per-song time by 12 hours by automating music annotation and preprocessing pipelines.","longDescription":"Built with Python, PyTorch, and TensorBoard, this project automated music annotation and preprocessing pipelines, reducing per-song preparation time by roughly 12 hours. I also implemented a speech model in PyTorch and trained it on GPU with TensorBoard, making the workflow faster and much easier to iterate on.","tech":["Python","PyTorch","TensorBoard","GPU Training","Audio Processing"],"mediaFrames":[{"type":"image","src":"/search-img/muto-banner.png","alt":"Generative AI singing voice synthesis visual"}],"links":[]},{"title":"Cisco Systems","type":"project","alias":"cisco-systems","imageAlias":"renew","headline":"Motors prototype developer trainee for digital twin analytics","timeline":"Nov 2023 - Feb 2024","searchDescription":"Developed a digital twin of industrial motor systems and improved anomaly detection accuracy by 25%.","longDescription":"At Cisco Systems, I developed a digital twin of industrial motor systems by integrating IoT telemetry with Azure IoT Hub and Azure Digital Twin for real-time predictive analytics. I improved anomaly detection accuracy by 25%, modeled sensor data in DTDL, and deployed Python Function Apps to improve maintenance forecasting reliability and load-balance prediction quality.","tech":["Azure IoT Hub","Azure Digital Twin","Python","DTDL","Predictive Analytics"],"links":[]},{"title":"Computational Neuroscience Lab at Virginia Tech (IMAGINE)","type":"project","alias":"imagine-lab","imageAlias":"blu3whale","headline":"EEG pipeline for musical and neurological exploration","timeline":"Jan 2024 - May 2024","searchDescription":"Built an EEG preprocessing and feature-extraction pipeline that improved motor-imagery classification accuracy by 18%.","longDescription":"As an undergraduate researcher in the IMAGINE lab, I worked on movement coding and EEG analysis to explore musical approaches for neurological research. I built an EEG preprocessing and feature-extraction pipeline in Python with MNE, applying ICA, band-pass filtering, and time-frequency features to improve motor-imagery classification accuracy by 18%.","tech":["Python","MNE","EEG","ICA","Signal Processing","Feature Extraction"],"links":[]},{"title":"Meta-consciousness for Test Takers and Success Seekers","type":"project","alias":"meta-consciousness","imageAlias":"rbc","headline":"Gap-year writing project with 1,000 books published","timeline":"Oct 2022 - Jan 2024","searchDescription":"Spent a gap year writing and publishing 1,000 books with Thaihabooks and received a recommendation from the CEO.","longDescription":"During my gap year, I wrote and published 1,000 books with Thaihabooks. The project stretched both creative discipline and long-form storytelling endurance, and it led to a recommendation from the company’s CEO.","tech":["Writing","Publishing","Storytelling","Creative Discipline"],"links":[]},{"title":"Institute for Creativity, Arts, and Technology","type":"project","alias":"icat-spatial-audio","imageAlias":"spatial-audio","bannerSrc":"/search-img/project-spatial-audio-hero.jpg","headline":"AI-driven spatial audio engine with sub-40 ms latency","timeline":"2024","searchDescription":"Developed a spatial audio engine that auto-positions and mixes up to 32 sources in 3D with lower localization error.","longDescription":"Using Whisper OpenAI, Facebook Demucs, Python, and PyTorch, I developed an AI-driven spatial audio engine that auto-positions and mixes up to 32 sources in 3D. The system achieved sub-40 ms end-to-end latency and reduced localization error by roughly 15-25% through generative scene priors.","tech":["Whisper","Facebook Demucs","Python","PyTorch","Spatial Audio","Low Latency"],"mediaFrames":[{"type":"image","src":"/search-img/project-spatial-audio-hero.jpg","alt":"Spatial audio project hero"},{"type":"image","src":"/search-img/project-spatial-audio-detail.png","alt":"Spatial audio project detail"}],"links":[]},{"title":"AI Housing Agent","type":"hackathon","alias":"ai-housing-agent","imageAlias":"winter-go","headline":"VT Hacks 2025 housing recommender with ranking and heatmaps","timeline":"VT Hacks 2025","searchDescription":"Matched Virginia Tech students to high-fit housing using compatibility scores, vector search, and diversified ranking.","longDescription":"Built with Python, FastAPI, Postgres/pgvector, Databricks, Gemini, deck.gl, h3-js, and Figma, this housing agent matched Virginia Tech students to high-fit housing through 0-100 compatibility scores and top-3 diversified recommendations. It also integrated interactive H3 heatmaps across Blacksburg inventory and generated editable outreach messages grounded in evidence JSON.","tech":["Python","FastAPI","Postgres","pgvector","Databricks","Gemini","deck.gl","h3-js"],"links":[]},{"title":"Deloitte Data Competition","type":"project","alias":"deloitte-data-competition","imageAlias":"deloitte","imageFit":"contain","headline":"Top 3 real-time fraud detection system on Azure","timeline":"March 2024 - March 2026","searchDescription":"Founded and led a team for the 2024 Deloitte competition, then extended the work into a 2026 systems flowchart and architecture view.","longDescription":"For the Deloitte Data Competition, I founded and led a team of four to build a real-time fraud detection system on Azure with modeling in MATLAB and dashboards in Tableau. The 2024 project earned a Top 3 award and improved anomaly-detection precision by 22% through supervised models in Azure ML pipelines and clearer visualization of high-risk transaction clusters. In 2026, I extended the work with a dedicated system flowchart and architecture view that captured the end-to-end workflow in a clearer visual format.","tech":["Azure","MATLAB","Tableau","Azure ML","Fraud Detection","Leadership"],"mediaFrames":[{"type":"image","src":"/search-img/alexa-connect-banner.png","alt":"Deloitte Data Competition 2024 presentation"},{"type":"image","src":"/search-img/deloitte-2026-banner.png","alt":"Deloitte Data Competition 2026 flowchart"}],"links":[]}]');

